design/implementation-uml.puml:
@startuml

package "Utilities" {
    class parse_gitignore <<Utility>> {
        "parses .gitignore file and extracts ignore patterns"
    }
    note right of parse_gitignore : Parses .gitignore file and extracts ignore patterns.

    class is_ignored <<Utility>> {
        "determines if a file path matches .gitignore patterns"
    }
    note right of is_ignored : Determines if a file path matches .gitignore patterns.

    class collect_files <<Utility>> {
        "Collects readable text files from a directory, skipping ignored or binary files."
    }
    note right of collect_files : Collects readable text files from a directory.

    class run <<Utility>> {
        "executes a shell command and prints it"
    }
    note right of run : Executes a shell command and prints it.

    class ensure_vsce <<Utility>> {
        "Ensures the @vscode/vsce tool is available and installs it if missing."
    }
    note right of ensure_vsce : Ensures @vscode/vsce tool availability.

    class read_version <<Utility>> {
        "retrieves the current version from package.json"
    }
    note right of read_version : Retrieves the current version from package.json.

    class preflight_checks <<Utility>> {
        "Validates project readiness for publishing by checking required files and fields."
    }
    note right of preflight_checks : Validates project readiness for publishing.

    class npm_install <<Utility>> {
        "Ensures Node.js dependencies are installed if missing"
    }
    note right of npm_install : Ensures Node.js dependencies are installed.

    class compile_ts <<Utility>> {
        "compiles TypeScript source code using NPM"
    }
    note right of compile_ts : Compiles TypeScript source code using NPM.

    class package_vsix <<Utility>> {
        "Packages a Visual Studio Code extension into a .vsix file."
    }
    note right of package_vsix : Packages a VS Code extension into a .vsix file.

    class workspaceRoot <<Utility>> {
        "retrieves the URI of the first open workspace folder in Visual Studio Code"
    }
    note right of workspaceRoot : Retrieves the URI of the first open workspace folder.

    class intentUri <<Utility>> {
        "returns a VS Code URI representing an intent"
    }
    note right of intentUri : Returns a VS Code URI representing an intent.

    class implUri <<Utility>> {
        "returns a URI object using Visual Studio Code's API"
    }
    note right of implUri : Returns a URI object using VS Code's API.

    class readIntentArchitecture <<Utility>> {
        "retrieves intent architecture information"
    }
    note right of readIntentArchitecture : Retrieves intent architecture information.

    class writeImplementationUml <<Utility>> {
        "generates a UML diagram and writes it to a file"
    }
    note right of writeImplementationUml : Generates a UML diagram and writes it to a file.
}

package "Controllers" {
    class main <<Controller>> {
        "Parses CLI arguments to package or publish a VS Code extension and executes the corresponding actions."
    }
    note right of main : Parses CLI arguments and executes actions.

    class handleDefaultPrompt <<Controller>> {
        "Handles user prompt and streams markdown instructions for architecture-related workflows."
    }
    note right of handleDefaultPrompt : Handles user prompt and streams markdown instructions.
}

package "Services" {
    class publish_extension <<Service>> {
        "Publishes an extension to the VS Code Marketplace."
    }
    note right of publish_extension : Publishes an extension to the VS Code Marketplace.

    class argoRequestHandler <<Service>> <<Adapter>> {
        "Handles incoming chat requests and produces a response."
    }
    note right of argoRequestHandler : Handles incoming chat requests and produces a response.

    class activate <<Service>> {
        "initializes and registers the extension's functionality within Visual Studio Code"
    }
    note right of activate : Initializes and registers the extension's functionality.

    class sendLlmRequestStreaming <<Service>> {
        "sends a streaming request to an LLM and processes the response"
    }
    note right of sendLlmRequestStreaming : Sends a streaming request to an LLM and processes the response.
}

package "Value Objects" {
    class CodeSymbolNode <<ValueObject>> {
        "Represents metadata and relationships for a code symbol in a source file."
    }
    note right of CodeSymbolNode : Represents metadata for a code symbol.

    class BusinessSummary <<ValueObject>> {
        "Defines a structure for summarizing business logic metadata."
    }
    note right of BusinessSummary : Defines a structure for summarizing business logic.

    class UmlNote <<ValueObject>> {
        "Represents a note attached to a PlantUML element."
    }
    note right of UmlNote : Represents a note attached to a PlantUML element.

    class SemanticUmlResult <<ValueObject>> {
        "Represents the result of a semantic UML analysis, including generated UML, summaries, notes, and call graph."
    }
    note right of SemanticUmlResult : Represents the result of a semantic UML analysis.
}

main --> npm_install
main --> ensure_vsce
main --> compile_ts
main --> preflight_checks
main --> package_vsix
main --> publish_extension

@enduml

