 *   3. Require the main agent to commit and return the commit id.
 *   4. Resolve source files changed by that commit.
 *   5. Extract implementation UML from real workspace code and persist it.
 */
export async function handleEvolve(
    request: vscode.ChatRequest,
    _context: vscode.ChatContext,
    stream: vscode.ChatResponseStream,
    token: vscode.CancellationToken,
): Promise<void> {
    stream.markdown('## рҹ”„ /evolve вҖ” Architecture Evolution\n\n');

    const intentFile = intentUri();
    try {
        await vscode.workspace.fs.stat(intentFile);
    } catch {
        stream.markdown(
            'вҡ пёҸ жүҫдёҚеҲ° `design/architecture-intent.puml`пјҢиҜ·е…ҲеҲӣе»әе®ғгҖӮ\n\n' +
            'зӨәдҫӢпјҡеңЁе·ҘдҪңеҢәж №зӣ®еҪ•дёӢеҲӣе»ә `design/architecture-intent.puml`пјҢеҶҷе…ҘжңҖж–°зҡ„жј”иҝӣеҗҺжһ¶жһ„ж„ҸеӣҫгҖӮ\n',
        );
        return;
    }

    const { commitId, extraContext } = parseCommitPrompt(request.prompt);

    if (!commitId) {
        const handoffPrompt = buildMainAgentHandoffPrompt(intentFile, 'evolve', extraContext);
        stream.markdown(
            '### Step 1 вҖ” Handoff To Copilot Main Agent\n\n' +
            'еҪ“еүҚзЁіе®ҡ VS Code API дёҚж”ҜжҢҒз”ұ Argo зӣҙжҺҘзј–зЁӢејҸжӢүиө· GitHub Copilot дё» agent е№¶зӯүеҫ…е…¶е®ҢжҲҗд»Јз Ғдҝ®ж”№гҖӮ\n\n' +
            'иҜ·е°ҶдёӢйқўиҝҷж®өжҢҮд»ӨдәӨз»ҷ Copilot дё» agent жү§иЎҢгҖӮArgo еҸӘжҺҘеҸ— **commit id** дҪңдёәдёӢдёҖжӯҘиҫ“е…ҘпјҢе№¶дјҡеҹәдәҺиҜҘ commit еҜ№зңҹе®һд»Јз ҒеҒҡе®һзҺ°жһ¶жһ„жҸҗеҸ–гҖӮ\n\n',
        );
        stream.markdown('```text\n' + handoffPrompt + '\n```\n\n');
        stream.markdown(
            'дё» agent е®ҢжҲҗеҗҺпјҢиҜ·йҮҚж–°иҝҗиЎҢпјҡ\n\n' +
            '`@argo /evolve commit:<commit-id>`\n',
        );
        return;
    }

    stream.markdown(`### Step 1 вҖ” Resolving commit \`${commitId}\` вҖҰ\n\n`);
    if (!(await commitExists(commitId))) {
        stream.markdown(`вқҢ жүҫдёҚеҲ° commit: \`${commitId}\`\n`);
        return;
    }

    const headCommit = await getHeadCommit();
    if (!headCommit.startsWith(commitId)) {
        stream.markdown(
            `вҡ пёҸ еҪ“еүҚе·ҘдҪңеҢә HEAD жҳҜ \`${headCommit.slice(0, 12)}\`пјҢдёҚжҳҜ \`${commitId}\`гҖӮ` +
            'Argo е°ҶеҹәдәҺ**еҪ“еүҚе·ҘдҪңеҢәдёӯиҝҷдәӣж–Үд»¶зҡ„е®һйҷ…еҶ…е®№**жҸҗеҸ–е®һзҺ°жһ¶жһ„пјҢиҖҢдёҚжҳҜд»Һ git еҜ№иұЎдёӯйҮҚе»әдёҙж—¶еҝ«з…§гҖӮ\n\n',
        );
    }

    const targetUris = await getChangedSourceUrisForCommit(commitId);
    if (targetUris.length === 0) {
        stream.markdown(
            `вҡ пёҸ commit \`${commitId}\` жІЎжңүжЈҖжөӢеҲ°еҸҜеҲҶжһҗзҡ„жәҗз Ғж–Үд»¶еҸҳжӣҙпјҢж— жі•жҸҗеҸ–е®һзҺ°жһ¶жһ„гҖӮ\n`,
        );
        return;
    }

    stream.markdown(
        `еҸ‘зҺ° **${targetUris.length}** дёӘеҸҳжӣҙжәҗз Ғж–Үд»¶пјҢејҖе§ӢеҹәдәҺзңҹе®һд»Јз ҒжҸҗеҸ–е®һзҺ°жһ¶жһ„гҖӮ\n\n`,
    );

    const engine = new DefaultSemanticUmlEngine();
    try {
        const result = await engine.extract({
            targetUris,
            incremental: true,
            token,
            stream,
        });

        const savedUri = await writeImplementationUml(result.plantUml);
        stream.markdown(
            `вң… еҹәдәҺ commit \`${commitId}\` зӣёе…ізңҹе®һд»Јз ҒжҸҗеҸ–зҡ„е®һзҺ°жһ¶жһ„е·ІиҮӘеҠЁеӯҳжЎЈиҮі [design/implementation-uml.puml](${savedUri.toString()})гҖӮ\n\n`,
        );
        stream.markdown(
            `> жҸҗеҸ–иҢғеӣҙпјҡ${targetUris.length} дёӘеҸҳжӣҙжәҗз Ғж–Үд»¶ В· иҖ—ж—¶ ${result.elapsedMs}ms\n`,
        );
    } catch (err) {
        if (err instanceof vscode.CancellationError) {
            stream.markdown('вҡ пёҸ Operation cancelled.\n');
            return;
        }
        stream.markdown(`вқҢ е®һзҺ°жһ¶жһ„жҸҗеҸ–еӨұиҙҘпјҡ\`${String(err)}\`\n`);
    }
}

