import * as vscode from 'vscode';
import { DefaultSemanticUmlEngine } from '../engine/defaultEngine';
import { StitchJudge } from '../engine/stitchJudge';
import { writeTraceabilityMatrix } from '../utils/workspaceFs';

/**
 * `/link` вҖ” Build Traceability Matrix
 *
 * Pipeline:
 *   1. User provides ArchiMate intent (after reviewing /baseline output).
 *   2. Run ExtractSemanticUML() to get current implementation UML.
 *   3. LLM maps each ArchiMate component to concrete code classes.
 *   4. Produce a TraceabilityMatrix with confidence scores.
 */
export async function handleLink(
    request: vscode.ChatRequest,
    _context: vscode.ChatContext,
    stream: vscode.ChatResponseStream,
    token: vscode.CancellationToken,
): Promise<void> {
    stream.markdown('## рҹ”— /link вҖ” Traceability Matrix\n\n');

    const archiMateIntent = request.prompt.trim();
    if (!archiMateIntent) {
        stream.markdown(
            'вҡ пёҸ Please provide your ArchiMate intent in the message.\n\n' +
            'Example:\n```\n@argo /link\n' +
            'Application Component "OrderService" serves Business Process "Place Order".\n' +
            'Application Component "PaymentGateway" serves Business Process "Process Payment".\n```\n',
        );
        return;
    }

    // в”Җв”Җ Step 1: Extract current implementation UML в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    stream.markdown('### Step 1 вҖ” Extracting implementation UML from workspace вҖҰ\n\n');
    const engine = new DefaultSemanticUmlEngine();

    let implementationUml: string;
    try {
        const result = await engine.extract({
            targetUris: [],
            incremental: false,
            token,
            stream,
        });
        implementationUml = result.plantUml;
    } catch (err) {
        if (err instanceof vscode.CancellationError) return;
        stream.markdown(`вқҢ Failed to extract UML: \`${String(err)}\`\n`);
        return;
    }

    stream.markdown('```plantuml\n' + implementationUml + '\n```\n\n');

    // в”Җв”Җ Step 2: Build traceability matrix в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    stream.markdown('### Step 2 вҖ” Building traceability matrix вҖҰ\n\n');
    const judge = new StitchJudge();

    try {
        const matrix = await judge.buildTraceabilityMatrix(
            archiMateIntent,
            implementationUml,
            token,
        );

        if (matrix.entries.length === 0) {
            stream.markdown('вҡ пёҸ No mappings could be established. Ensure your ArchiMate intent references components found in the codebase.\n');
            return;
        }

        const matrixUri = await writeTraceabilityMatrix(matrix);
        stream.markdown('### рҹ“Ӣ Traceability Matrix\n\n');
        stream.markdown(
            `вң… Traceability Matrix е·ІиҮӘеҠЁеӯҳжЎЈиҮі [design/traceability-matrix.md](${matrixUri.toString()})гҖӮ\n\n`,
        );

        stream.markdown(
            `\n> Generated at ${matrix.generatedAt.toISOString()} В· ${matrix.entries.length} mapping(s)\n\n` +
            '> рҹ’Ў **Next step:** Review low-confidence mappings, then use `@argo /init` or `@argo /evolve` to enforce stitching.\n',
        );
    } catch (err) {
        if (err instanceof vscode.CancellationError) return;
        stream.markdown(`вқҢ Failed to build traceability matrix: \`${String(err)}\`\n`);
    }
}

