import * as vscode from 'vscode';

const COMMIT_ID_PATTERN = /(?:^|\s)(?:commit\s*:\s*)?([0-9a-f]{7,40})(?=$|\s)/i;

export function parseCommitPrompt(prompt: string): { commitId?: string; extraContext: string } {
    const trimmed = prompt.trim();
    if (!trimmed) {
        return { extraContext: '' };
    }

    const match = trimmed.match(COMMIT_ID_PATTERN);
    if (!match) {
        return { extraContext: trimmed };
    }

    const commitId = match[1];
    const extraContext = trimmed.replace(match[0], ' ').replace(/\s+/g, ' ').trim();
    return { commitId, extraContext };
}

export function buildMainAgentHandoffPrompt(
    intentFile: vscode.Uri,
    workflow: 'init' | 'evolve',
    extraContext: string,
): string {
    const workflowSpecificSteps = workflow === 'init'
        ? [
            '2. йҳ…иҜ»иҜҘж–Үд»¶е№¶еңЁеҪ“еүҚе·ҘдҪңеҢәе®һзҺ°еҜ№еә”д»Јз Ғж”№еҠЁгҖӮ',
        ]
        : [
            '2. йҳ…иҜ»иҜҘж–Үд»¶пјҢе№¶з»“еҗҲеҪ“еүҚе·ҘдҪңеҢәе·Іжңүд»Јз Ғе®һж–ҪеўһйҮҸжһ¶жһ„жј”иҝӣгҖӮ',
            '3. дёҘж јжҺ§еҲ¶ж”№еҠЁиҢғеӣҙпјҢеҸӘдҝ®ж”№е®һзҺ°иҜҘжһ¶жһ„жј”иҝӣжүҖеҝ…йңҖзҡ„д»Јз ҒгҖӮ',
        ];

    const lines = [
        'иҜ·дҪңдёә Copilot дё» agent е®ҢжҲҗд»ҘдёӢе·ҘдҪңпјҡ',
        `1. е°Ҷ ${intentFile.fsPath} дҪңдёәе”ҜдёҖзҡ„жһ¶жһ„ж„ҸеӣҫжқҘжәҗпјҢдёҚиҰҒиҰҒжұӮз”ЁжҲ·еҶҚж¬ЎзІҳиҙҙе®Ңж•ҙж„ҸеӣҫеҶ…е®№гҖӮ`,
        ...workflowSpecificSteps,
        `${workflow === 'init' ? '3' : '4'}. ж”№еҠЁе®ҢжҲҗеҗҺпјҢеҝ…йЎ»жү§иЎҢ git commitгҖӮ`,
        `${workflow === 'init' ? '4' : '5'}. еӣһеӨҚж—¶еҝ…йЎ»иҝ”еӣһпјҡ`,
        '   - commit id',
        '   - з®ҖзҹӯеҸҳжӣҙж‘ҳиҰҒ',
        `${workflow === 'init' ? '5' : '6'}. дёҚиҰҒеҸӘиҫ“еҮәе»әи®®пјҢеҝ…йЎ»зңҹжӯЈдҝ®ж”№е·ҘдҪңеҢәд»Јз Ғе№¶жҸҗдәӨгҖӮ`,
    ];

    if (extraContext) {
        lines.push(`${workflow === 'init' ? '6' : '7'}. йўқеӨ–дёҠдёӢж–Үпјҡ${extraContext}`);
    }

    return lines.join('\n');
}

